<path>/Users/dmitry/WebstormProjects/zephyr-budget-app/client/src/components/Layout/MainLayout.tsx</path>
<content>import { useState, useCallback, useMemo } from 'react';
import { Outlet } from 'react-router-dom';
import { Sidebar } from 'Components/Sidebar';
import styles from './MainLayout.module.scss';

export const MainLayout = () => {
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  const handleSidebarToggle = useCallback(() => {
    setIsSidebarCollapsed((prev) => !prev);
  }, []);

  const mainClassName = useMemo(
    () =>
      `${styles.main} ${isSidebarCollapsed ? styles.sidebarCollapsed : ''}`,
    [isSidebarCollapsed]
  );

  return (
    <div className={styles.layout}>
      <Sidebar
        isCollapsed={isSidebarCollapsed}
        onToggle={handleSidebarToggle}
      />
      <main className={mainClassName}>
        <Outlet />
      </main>
    </div>
  );
};
</content>
</write_file>

